head.script:
//
(function(){
  var t='system';
  try {
    t = localStorage.getItem('tvc-theme') || 'system';
  } catch(e) {
    t = 'system';
  }
  if(!/^(system|light|dark)$/.test(t)) t='system';
  var systemDark = false;
  try {
    systemDark = !!(window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches);
  } catch(e) {
    systemDark = false;
  }
  var resolved = t === 'dark' ? 'dark' : (t === 'light' ? 'light' : (systemDark ? 'dark' : 'light'));
  document.documentElement.setAttribute('data-theme', resolved);
  document.documentElement.setAttribute('data-theme-choice', t);
  document.documentElement.style.colorScheme = resolved;
  var vcThemeMeta = document.getElementById('vc-theme-color');
  if(vcThemeMeta) vcThemeMeta.setAttribute('content', resolved === 'dark' ? '#101010' : '#ffffff');
})();
//

//
var numposts11 = 20;
function vcBloggerImageSize(url, size){
  url = String(url || '');
  size = size || 's640';
  if(!url) return '';
  return url
    .replace(/\/s\d+(?:\-[^\/]+)?\//, '/' + size + '/')
    .replace(/\/w\d+\-h\d+(?:\-[^\/]+)?\//, '/' + size + '/')
    .replace(/=s\d+(?:\-[^&]+)?/, '=' + size)
    .replace(/=w\d+\-h\d+(?:\-[^&]+)?/, '=' + size);
}
function vcStripHTML(html, maxWords){
  var source = String(html || '').replace(/<iframe[\s\S]*?<\/iframe>/gi,'').replace(/<script[\s\S]*?<\/script>/gi,'').replace(/<style[\s\S]*?<\/style>/gi,'');
  var holder = document.createElement('div');
  holder.innerHTML = source;
  var text = (holder.textContent || holder.innerText || '').replace(/\s+/g,' ').trim();
  var words = text.split(' ');
  return words.slice(0, maxWords || 28).join(' ') + (words.length > (maxWords || 28) ? '…' : '');
}
function vcEntryLink(entry){
  if(!entry.link) return '#';
  for(var i=0;i<entry.link.length;i++){ if(entry.link[i].rel === 'alternate') return entry.link[i].href; }
  return entry.link[0].href;
}
function vcEntryImage(entry, size){
  size = size || 's640';
  if(entry && entry.media$thumbnail && entry.media$thumbnail.url) return vcBloggerImageSize(entry.media$thumbnail.url, size);
  var content = entry && entry.content && entry.content.$t || '';
  var s = content.match(/<img[^>]+srcset=["']([^"']+)["']/i);
  if(s){
    var parts = s[1].split(',').map(function(part){
      var bits = part.trim().split(/\s+/);
      return {url: bits[0], width: parseInt((bits[1] || '0').replace(/\D/g,''), 10) || 0};
    }).sort(function(a,b){ return b.width - a.width; });
    if(parts[0] && parts[0].url) return vcBloggerImageSize(parts[0].url, size);
  }
  var m = content.match(/<img[^>]+(?:data-src|src)=["']([^"']+)["']/i);
  if(m) return vcBloggerImageSize(m[1], size);
  return '';
}
var relatedTitles = [], relatedUrls = [], thumburl = [], relatedTitlesNum = 0, relatedFeedsPending = 0, relatedPrintRequested = false, relatedCurrentUrl = '', relatedPrintTimer = null;
var defaultnoimage = 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEgqXde-worQuTJ8HHnBDZDs6PNRypLtaVHWiC6aHMqOU2pCcyHiYijh6gCi59mt3tqGgI_7MTY8RSlG7PkuDiP3r73Mzl2xVzODlzHy5pB2s7whR4ZeCpma_3xq70VGVz_q-7YuVPdSX37m/s1600/no-image-found.jpg';
var maxresults = 3;
function vcEscape(s){ return String(s || '').replace(/[&<>"]/g, function(c){ return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]; }); }
function vcDecodeHTML(value){ var el = document.createElement('textarea'); el.innerHTML = value || ''; return el.value; }
function vcFirstImageFromHTML(html){ var m = String(html || '').match(/<img[^>]+(?:data-src|src)=["']([^"']+)["']/i); return m ? m[1] : ''; }
function vcLimitLabelHTML(tag, maxLabels){
  var raw = String(tag || '');
  if(!raw) return '';
  var holder = document.createElement('div');
  holder.innerHTML = raw;
  var links = Array.prototype.slice.call(holder.querySelectorAll('a')).slice(0, maxLabels || 3);
  return links.map(function(a){
    var href = vcEscape(a.getAttribute('href') || '#');
    var text = vcEscape(a.textContent || a.innerText || '');
    return '<a href="' + href + '" rel="tag">' + text + '</a>';
  }).join('');
}
function createSummaryAndThumb(pID, title, url, date, comment, tag){
  var div = document.getElementById(pID); if(!div) return;
  var body = div.innerHTML || '';
  var img = vcFirstImageFromHTML(body);
  var iframe = body.match(/<iframe[^>]+src=["']([^"']+)["'][^>]*>/i);
  var excerpt = vcStripHTML(body.replace(/<img[\s\S]*?>/ig,'').replace(/<iframe[\s\S]*?<\/iframe>/ig,''), 50);
  var labelHtml = vcLimitLabelHTML(tag, 3);
  var safeUrl = vcEscape(url);
  var safeTitle = vcEscape(vcDecodeHTML(title));
  var safeDate = vcEscape(date);
  var media = '';
  if(img){ media = '<div class="post-image"><a href="'+safeUrl+'"><img loading="lazy" decoding="async" src="'+vcEscape(img)+'" alt="'+safeTitle+'"/></a></div>'; }
  else if(iframe){ media = '<div class="post-image"><iframe loading="lazy" src="'+vcEscape(iframe[1])+'" allowfullscreen="allowfullscreen"></iframe></div>'; }
  div.className = (div.className ? div.className + ' ' : '') + 'index-summary';
  if(div.parentElement && div.parentElement.classList && !div.parentElement.classList.contains('index-card')){ div.parentElement.classList.add('index-card'); }
  div.innerHTML = '<div class="post-header"><div class="post-tag">'+labelHtml+'</div><h2><a href="'+safeUrl+'">'+safeTitle+'</a></h2><div class="meta-date">'+safeDate+'</div></div>' + media + '<div class="post-entry"><p>'+excerpt+'...</p><p><a class="more-link" href="'+safeUrl+'">Continue Reading</a></p></div>';
  div.style.display = 'block';
}
function vcQueueRelatedFeed(){
  relatedFeedsPending++;
}
function vcRelatedMaybePrint(){
  if(!relatedPrintRequested || relatedFeedsPending > 0) return;
  if(relatedPrintTimer){ window.clearTimeout(relatedPrintTimer); relatedPrintTimer = null; }
  removeRelatedDuplicates_thumbs();
  printRelatedLabels_thumbs(relatedCurrentUrl);
}
function related_results_labels_thumbs(json){
  try {
    if(json && json.feed && json.feed.entry){
      for(var i=0;i<json.feed.entry.length;i++){
        var entry = json.feed.entry[i], href = vcEntryLink(entry), title = entry.title && entry.title.$t || 'Related post';
        if(!href) continue;
        relatedTitles.push(title.length>60 ? title.substring(0,60)+'…' : title); relatedUrls.push(href); thumburl.push(vcEntryImage(entry, 's480') || defaultnoimage);
      }
    }
  } finally {
    if(relatedFeedsPending > 0) relatedFeedsPending--;
    vcRelatedMaybePrint();
  }
}
function removeRelatedDuplicates_thumbs(){
  var seen={}, t=[], u=[], th=[];
  for(var i=0;i<relatedUrls.length;i++){ if(!seen[relatedUrls[i]]){ seen[relatedUrls[i]]=true; t.push(relatedTitles[i]); u.push(relatedUrls[i]); th.push(thumburl[i]); } }
  relatedTitles=t; relatedUrls=u; thumburl=th;
}
function printRelatedLabels_thumbs(current){
  relatedPrintRequested = true;
  relatedCurrentUrl = current || relatedCurrentUrl || '';
  if(relatedFeedsPending > 0){
    if(!relatedPrintTimer){ relatedPrintTimer = window.setTimeout(function(){ relatedFeedsPending = 0; vcRelatedMaybePrint(); }, 3000); }
    return;
  }
  var max = (typeof maxresults !== 'undefined') ? maxresults : 3, printed = 0, html = '';
  for(var i=0;i<relatedUrls.length && printed<max;i++){
    if(relatedUrls[i] === relatedCurrentUrl) continue;
    var img = vcBloggerImageSize(thumburl[i] || defaultnoimage, 's480');
    var safeRelatedUrl = vcEscape(relatedUrls[i]);
    html += '<article class="item-related related-journey-card"><a class="related-thumb" href="'+safeRelatedUrl+'"><img loading="lazy" decoding="async" width="320" height="180" src="'+vcEscape(img)+'" alt="'+vcEscape(relatedTitles[i])+'"/></a><div class="related-body"><h3><a href="'+safeRelatedUrl+'">'+vcEscape(relatedTitles[i])+'</a></h3><a class="related-read" href="'+safeRelatedUrl+'">Continue reading →</a></div></article>';
    printed++;
  }
  var target = document.querySelector('.post-related .related-results');
  if(target) target.innerHTML = html;
  relatedTitles=[]; relatedUrls=[]; thumburl=[]; relatedPrintRequested = false;
}
function vcInitFeaturedCarousel(){
  var wrap = document.getElementById('featured-posts');
  if(!wrap || wrap.dataset.carouselReady === '1') return;
  var track = wrap.querySelector('.featured-posts-track');
  if(!track) return;
  var cards = Array.prototype.slice.call(track.querySelectorAll('.featured-card'));
  if(cards.length < 2){ wrap.classList.add('is-single'); return; }
  wrap.dataset.carouselReady = '1';
  var index = 0, timer = null, restartTimer = null, visible = true;
  var reducedMotion = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  var live = document.createElement('span');
  live.className = 'sr-only featured-carousel-live';
  live.setAttribute('aria-live','off');
  wrap.appendChild(live);
  function perView(){ return window.matchMedia('(max-width:720px)').matches ? 1 : (window.matchMedia('(max-width:960px)').matches ? 2 : 3); }
  function maxIndex(){ return Math.max(0, cards.length - perView()); }
  function gap(){ var g = window.getComputedStyle(track).gap || window.getComputedStyle(track).columnGap || '18px'; g = parseFloat(g); return isNaN(g) ? 18 : g; }
  function apply(){
    window.requestAnimationFrame(function(){
      var max = maxIndex();
      if(index > max) index = 0;
      if(index < 0) index = max;
      var width = cards[0].getBoundingClientRect().width;
      if(!width || width < 10){ window.setTimeout(apply, 100); return; }
      track.style.transform = 'translateX(-' + (index * (width + gap())) + 'px)';
      if(live && live.getAttribute('aria-live') === 'polite' && cards[index]){
        var h = cards[index].querySelector('h3');
        live.textContent = h ? 'Featured post: ' + h.textContent : 'Featured post changed';
      }
    });
  }
  function next(){ index = index >= maxIndex() ? 0 : index + 1; apply(); }
  function prev(){ index = index <= 0 ? maxIndex() : index - 1; apply(); }
  function stop(){ if(timer){ window.clearInterval(timer); timer = null; } }
  function start(){ stop(); if(!reducedMotion && visible && maxIndex() > 0){ timer = window.setInterval(next, 4500); } }
  function pauseThenResume(){ stop(); if(restartTimer) window.clearTimeout(restartTimer); restartTimer = window.setTimeout(start, 6500); }
  function addButton(cls, label, icon, handler){
    var btn = document.createElement('button');
    btn.type = 'button'; btn.className = 'featured-carousel-btn ' + cls; btn.setAttribute('aria-label', label); btn.innerHTML = '<i class="fa-solid ' + icon + '" aria-hidden="true"></i>';
    btn.addEventListener('click', function(){ if(live) live.setAttribute('aria-live','polite'); handler(); pauseThenResume(); });
    wrap.appendChild(btn);
  }
  addButton('featured-carousel-prev','Previous featured post','fa-angle-left',prev);
  addButton('featured-carousel-next','Next featured post','fa-angle-right',next);
  function waitForImages(done){
    var imgs = Array.prototype.slice.call(track.querySelectorAll('img'));
    if(!imgs.length){ done(); return; }
    var remaining = imgs.length;
    function one(){ remaining--; if(remaining <= 0) done(); }
    imgs.forEach(function(img){ if(img.complete){ one(); } else { img.addEventListener('load', one, {once:true}); img.addEventListener('error', one, {once:true}); } });
  }
  waitForImages(function(){ apply(); start(); });
  var resizeTimer;
  window.addEventListener('resize', function(){ window.clearTimeout(resizeTimer); resizeTimer = window.setTimeout(function(){ apply(); start(); }, 150); });
  wrap.addEventListener('mouseenter', stop);
  wrap.addEventListener('mouseleave', start);
  wrap.addEventListener('focusin', stop);
  wrap.addEventListener('focusout', start);
  wrap.addEventListener('touchstart', pauseThenResume, {passive:true});
  if('IntersectionObserver' in window){
    new IntersectionObserver(function(entries){ visible = entries[0] && entries[0].isIntersecting; visible ? start() : stop(); }, {threshold:.2}).observe(wrap);
  }
}
function showrecentposts1(json){
  var target = document.getElementById('featured-posts'); if(!target || !json || !json.feed || !json.feed.entry) return;
  var cards = json.feed.entry.slice(0,numposts11).map(function(entry, i){
    var title = entry.title && entry.title.$t || 'Post';
    var href = vcEntryLink(entry);
    var img = vcEntryImage(entry, 's640');
    var excerpt = vcStripHTML(entry.summary && entry.summary.$t || entry.content && entry.content.$t || '', 26);
    var safeHref = vcEscape(href);
    var safeTitle = vcEscape(title);
    var safeImg = img ? vcEscape(img) : '';
    var safeExcerpt = vcEscape(excerpt);
    var safeAlt = safeTitle || 'Featured travel post';
    return '<article class="featured-card"><a href="'+safeHref+'">'+(img?'<img loading="'+(i<3?'eager':'lazy')+'" decoding="async" src="'+safeImg+'" alt="'+safeAlt+'"/>':'')+'<div class="featured-card-body"><h3>'+safeTitle+'</h3><p>'+safeExcerpt+'</p></div></a></article>';
  }).join('');
  target.innerHTML = '<div class="featured-posts-track">' + cards + '</div>';
  vcInitFeaturedCarousel();
}
//

body.script:
//
(function(){
  function ready(fn){ if(document.readyState !== 'loading') fn(); else document.addEventListener('DOMContentLoaded', fn); }
  ready(function(){
    document.body.classList.add('vc-modern-theme');
	var vcThemeToggles = Array.prototype.slice.call(document.querySelectorAll('.theme-switch'));
	var vcThemeToggleLabels = Array.prototype.slice.call(document.querySelectorAll('.theme-switch-label'));
	var vcThemeLive = document.getElementById('vc-theme-live');
	if(!vcThemeLive){
	  vcThemeLive = document.createElement('div');
	  vcThemeLive.id = 'vc-theme-live';
	  vcThemeLive.className = 'sr-only';
	  vcThemeLive.setAttribute('aria-live','polite');
	  vcThemeLive.setAttribute('aria-atomic','true');
	  document.body.appendChild(vcThemeLive);
	}
	var vcThemeMedia = window.matchMedia ? window.matchMedia('(prefers-color-scheme: dark)') : null;
	var vcThemeMeta = document.getElementById('vc-theme-color');
	var vcLogoLightUrl = 'https://blogger.googleusercontent.com/img/a/AVvXsEhpuoqWPunqT2G8FZ-bee53TsfGPItivlFKOJnGopUUpx7HK1gOkVRsuC-bG9AR9zRovRhfQUBUzHRrkhuvLBhzi7QBeqSeqeuGiKkSQO8JRZNyqYXp6-AjCCridYf4lbLwI8Z59dihVPOvGGGevUDLtGJ0IHStGMcuhCDegwZ629QeLK3hzODQSJvMhDX5=s16000';
	var vcLogoDarkUrl = 'https://blogger.googleusercontent.com/img/a/AVvXsEiNrtgXbLtQB9CzItrxMJD9CTAg6cTSSEMyV9pPBpZs4yW7OmtaZ1uTCzPiY_GrFMqKOu3LbvwWsq2Lw_CIIvyNoJw4_v4p4nmo5GEZRa5VRTpCAwipFn36Pgn1sjZlBSQc4TZqKLlmFvneJmzA67bqrhWLeHsPMuEPVTs0QLE7XLZBLp6Ft7ZHqP5ReFx5=s16000';
	var vcLogoImages = function(){
	  return Array.prototype.slice.call(document.querySelectorAll('#logo img, .logo_h img'));
	};
	var vcUpdateLogo = function(effective){
	  var src = effective === 'dark' ? vcLogoDarkUrl : vcLogoLightUrl;
	  vcLogoImages().forEach(function(img){
	    if(!img) return;
	    if(img.getAttribute('src') !== src) img.setAttribute('src', src);
	    img.setAttribute('width','778');
	    img.setAttribute('height','332');
	    img.setAttribute('decoding','async');
	    if(!img.getAttribute('alt')) img.setAttribute('alt','The Vagabond Couple');
	  });
	};
	function vcStoredTheme(){
	  var t='system';
	  try { t = localStorage.getItem('tvc-theme') || 'system'; } catch(e) { t='system'; }
	  return /^(system|light|dark)$/.test(t) ? t : 'system';
	}
	function vcResolvedTheme(value){
	  if(value === 'dark' || value === 'light') return value;
	  return (vcThemeMedia && vcThemeMedia.matches) ? 'dark' : 'light';
	}
	function vcToggleTarget(resolved){
	  return resolved === 'dark' ? 'light' : 'dark';
	}
	function vcUpdateThemeToggle(value, resolved){
	  var next = vcToggleTarget(resolved);
	  var modeText = value === 'system' ? 'follows device settings' : 'is forced to ' + value;
	  var label = 'Theme ' + modeText + '. Current theme is ' + resolved + '. Activate to switch to ' + next + '.';
	  vcThemeToggles.forEach(function(toggle){
	    toggle.setAttribute('data-effective', resolved);
	    toggle.setAttribute('aria-label', label);
	    toggle.setAttribute('title', 'Switch to ' + next + ' theme');
	  });
	  vcThemeToggleLabels.forEach(function(labelEl){ labelEl.textContent = label; });
	}
	function vcApplyTheme(value, persist, announce){
	  if(!/^(system|light|dark)$/.test(value)) value='system';
	  var resolved = vcResolvedTheme(value);
	  document.documentElement.setAttribute('data-theme', resolved);
	  document.documentElement.setAttribute('data-theme-choice', value);
	  document.documentElement.style.colorScheme = resolved;
	  if(vcThemeMeta) vcThemeMeta.setAttribute('content', resolved === 'dark' ? '#101010' : '#ffffff');
	  vcUpdateLogo(resolved);
	  vcUpdateThemeToggle(value, resolved);
	  if(persist){ try { localStorage.setItem('tvc-theme', value); } catch(e) {} }
	  if(announce && vcThemeLive) vcThemeLive.textContent = 'Theme changed to ' + value;
	}
	vcApplyTheme(vcStoredTheme(), false, false);
	vcThemeToggles.forEach(function(toggle){
	  toggle.addEventListener('click', function(){
	    var current = vcStoredTheme();
	    var resolved = vcResolvedTheme(current);
	    vcApplyTheme(vcToggleTarget(resolved), true, true);
	  });
	});
	if(vcThemeMedia){
	  var vcSystemListener = function(){ if(vcStoredTheme() === 'system') vcApplyTheme('system', false, false); };
	  if(vcThemeMedia.addEventListener) vcThemeMedia.addEventListener('change', vcSystemListener);
	  else if(vcThemeMedia.addListener) vcThemeMedia.addListener(vcSystemListener);
	}

	var mobileSearchTrigger = document.querySelector('.mobile-search-trigger');
	var mobileSearchForm = document.getElementById('top-search-form');
	var mobileSearchInput = mobileSearchForm ? mobileSearchForm.querySelector('input[name="q"]') : null;
	var mobileSearchBack = mobileSearchForm ? mobileSearchForm.querySelector('.mobile-search-back') : null;
	var mobileSearchClose = mobileSearchForm ? mobileSearchForm.querySelector('.mobile-search-close') : null;
	var mobileSearchPreviousFocus = null;
	var mobileSearchMQ = window.matchMedia ? window.matchMedia('(max-width:720px)') : null;
	var syncMobileSearchAria = function(open){
	  if(!mobileSearchForm) return;
	  var isMobile = mobileSearchMQ ? mobileSearchMQ.matches : (window.innerWidth <= 720);
	  mobileSearchForm.setAttribute('aria-hidden', (isMobile && !open) ? 'true' : 'false');
	};
	syncMobileSearchAria(false);
	if(mobileSearchMQ){
	  var searchMqListener = function(){ syncMobileSearchAria(document.body.classList.contains('vc-mobile-search-open')); };
	  if(mobileSearchMQ.addEventListener) mobileSearchMQ.addEventListener('change', searchMqListener);
	  else if(mobileSearchMQ.addListener) mobileSearchMQ.addListener(searchMqListener);
	}
	var mobileSearchFocusable = function(){
	  if(!mobileSearchForm) return [];
	  return Array.prototype.slice.call(mobileSearchForm.querySelectorAll('button, input, [href], [tabindex]:not([tabindex="-1"])')).filter(function(el){
	    return !el.disabled && el.offsetParent !== null;
	  });
	};
	var setMobileSearchOpen = function(open){
	  document.body.classList.toggle('vc-mobile-search-open', open);
	  if(mobileSearchTrigger) mobileSearchTrigger.setAttribute('aria-expanded', open ? 'true' : 'false');
	  syncMobileSearchAria(open);
	  if(open){
	    mobileSearchPreviousFocus = document.activeElement;
	    window.setTimeout(function(){ if(mobileSearchInput) mobileSearchInput.focus(); }, 0);
	  } else {
	    if(mobileSearchInput) mobileSearchInput.blur();
	    if(mobileSearchTrigger) mobileSearchTrigger.focus();
	  }
	};
	if(mobileSearchTrigger && mobileSearchForm){
	  mobileSearchTrigger.addEventListener('click', function(){ setMobileSearchOpen(true); });
	  if(mobileSearchBack) mobileSearchBack.addEventListener('click', function(){ setMobileSearchOpen(false); });
	  if(mobileSearchClose) mobileSearchClose.addEventListener('click', function(){
	    if(mobileSearchInput && mobileSearchInput.value){ mobileSearchInput.value = ''; mobileSearchInput.focus(); }
	    else { setMobileSearchOpen(false); }
	  });
	  mobileSearchForm.addEventListener('keydown', function(e){
	    if(e.key !== 'Tab' || !document.body.classList.contains('vc-mobile-search-open')) return;
	    var focusables = mobileSearchFocusable();
	    if(!focusables.length) return;
	    var first = focusables[0];
	    var last = focusables[focusables.length - 1];
	    if(e.shiftKey && document.activeElement === first){
	      e.preventDefault();
	      last.focus();
	    } else if(!e.shiftKey && document.activeElement === last){
	      e.preventDefault();
	      first.focus();
	    }
	  });
	  document.addEventListener('keydown', function(e){
	    if(e.key === 'Escape' && document.body.classList.contains('vc-mobile-search-open')){
	      setMobileSearchOpen(false);
	    }
	  });
	}

    var menu = document.querySelector('.menu-mobile');
    var nav = document.getElementById('navigation-wrapper');
    if(menu && nav){
      menu.setAttribute('role','button'); menu.setAttribute('tabindex','0'); menu.setAttribute('aria-expanded','false'); menu.setAttribute('aria-controls','navigation-wrapper');
      document.body.classList.remove('mobile-nav-open');
      var firstNavLink = function(){ return nav.querySelector('a, button, input, select, textarea, [tabindex]:not([tabindex="-1"])'); };
      var setMenuOpen = function(open){
        document.body.classList.toggle('mobile-nav-open', open);
        menu.setAttribute('aria-expanded', open ? 'true':'false');
        if(open){
          window.setTimeout(function(){ var first = firstNavLink(); if(first) first.focus(); }, 0);
        } else {
          menu.focus();
        }
      };
      var toggle = function(){ setMenuOpen(!document.body.classList.contains('mobile-nav-open')); };
      menu.addEventListener('click', toggle);
      menu.addEventListener('keydown', function(e){ if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); toggle(); }});
      document.addEventListener('keydown', function(e){ if(e.key === 'Escape' && document.body.classList.contains('mobile-nav-open')){ setMenuOpen(false); }});
    }
    var topSocial = document.querySelector('#top-social .widget-content');
    var footerSocial = document.querySelector('#footer-social .socialzz');
    if (topSocial && footerSocial && !footerSocial.children.length) {
      footerSocial.innerHTML = topSocial.innerHTML;
      footerSocial.querySelectorAll('a[target="_blank"]').forEach(function(a){ a.setAttribute('rel','noopener noreferrer'); });
    }
    document.querySelectorAll('img').forEach(function(img, i){ if(!img.hasAttribute('decoding')) img.setAttribute('decoding','async'); if(i>0 && !img.hasAttribute('loading')) img.setAttribute('loading','lazy'); });
    document.querySelectorAll('a.to-top').forEach(function(a){ a.addEventListener('click', function(e){ e.preventDefault(); window.scrollTo({top:0, behavior:'smooth'}); }); });
  });
})();
//
